const j = $input.all()[0].json;

// Update this path if your AI Agent output uses a different key
const raw =
  j.output ??
  j.text ??
  j.response ??
  j.message?.content ??
  j.choices?.[0]?.message?.content ??
  j.data?.choices?.[0]?.message?.content;

if (!raw) {
  throw new Error("Could not find AI Agent output text. Check AI Agent node output fields.");
}

let txt = String(raw).trim();

// Remove markdown fences if any
txt = txt
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```$/i, "")
  .trim();

// Extract JSON object boundaries
const start = txt.indexOf("{");
const end = txt.lastIndexOf("}");

if (start === -1 || end === -1 || end <= start) {
  throw new Error(
    "No JSON object boundaries found. Output starts with:\n" + txt.slice(0, 800)
  );
}

let candidate = txt.slice(start, end + 1);

// Normalise common JSON issues
candidate = candidate
  .replace(/[“”]/g, '"')
  .replace(/[‘’]/g, "'")
  .replace(/,\s*([}\]])/g, "$1")
  .replace(/[\uFEFF\u200B\u200C\u200D]/g, "")
  .trim();

let parsed;
try {
  parsed = JSON.parse(candidate);
} catch (err) {
  throw new Error("AI output JSON failed to parse. Candidate starts:\n" + candidate.slice(0, 1200));
}

// Basic validations
function expect(cond, msg) {
  if (!cond) throw new Error(msg);
}

expect(typeof parsed.summary === "string", "summary must be a string");
expect(parsed.level && typeof parsed.level === "object", "level must be an object");
expect(parsed.readinessWillingness && typeof parsed.readinessWillingness === "object", "readinessWillingness must be an object");
expect(Array.isArray(parsed.dimensionInsights), "dimensionInsights must be an array");
expect(Array.isArray(parsed.tagInsights), "tagInsights must be an array");
expect(parsed.recommendations && typeof parsed.recommendations === "object", "recommendations must be an object");
expect(parsed.vclPositioning && typeof parsed.vclPositioning === "object", "vclPositioning must be an object");

// Enforce counts
expect(parsed.dimensionInsights.length === 4, "dimensionInsights must contain exactly 4 items");
expect(parsed.tagInsights.length === 2, "tagInsights must contain exactly 2 items");

// No readiness/willingness inside dimensions
for (const d of parsed.dimensionInsights) {
  expect(typeof d.dimensionKey === "string", "dimensionKey must be string");
  expect(typeof d.dimensionTitle === "string", "dimensionTitle must be string");
  expect(typeof d.scorePercent === "number", "scorePercent must be number");
  expect(typeof d.strengthOrGap === "string", "strengthOrGap must be string");
  expect(typeof d.insight === "string", "insight must be string");
  expect(d.signals === undefined, "dimensionInsights must not include signals (readiness/willingness are assessment-level only)");
}

return [{ json: parsed }];

const incoming = $input.all()[0].json;
const body = incoming.body ?? incoming;

if (!body.participant || !body.scores || !Array.isArray(body.questions)) {
  throw new Error(
    "Missing expected fields: participant, scores, questions. Got: " +
      JSON.stringify(body, null, 2)
  );
}

const participant = body.participant;
const scores = body.scores;
const questions = body.questions;

const prepared = {
  participant: {
    domain: participant.domain || "N/A",
    originalWebsite: participant.originalWebsite || "N/A",
  },
  participantContext: {
    department: participant.department || "Unspecified"
  },
  scores: {
    overallPercent: scores.overallPercent,
    levelNumber: scores.levelNumber,
    levelLabel: scores.levelLabel,
    dimensions: scores.dimensions || [],
    tags: scores.tags || []
  },
  questionEvidence: questions.map(q => ({
    questionKey: q.questionKey,
    dimensionKey: q.dimensionKey,
    dimensionTitle: q.dimensionTitle,
    tags: q.tags,
    answerGrade: q.answerGrade,
    answerLabel: q.answerLabel,
    questionText: q.questionText
  }))
};

return [{ json: { prepared } }];
